function renderReports(){let cs=db.orders.filter(o=>!o.deletedAt).map(o=>({o,c:calc(o)})),active=cs.filter(x=>!['Hoàn công','Lưu trữ'].includes(x.o.stage)),completed=cs.filter(x=>['Hoàn công','Lưu trữ'].includes(x.o.stage)),metrics=[['Đơn đang chạy',active.length],['Đã hoàn công',completed.length],['Giá trị đang chạy',money(active.reduce((s,x)=>s+x.c.revenue,0))],['Tổng đã thu',money(cs.reduce((s,x)=>s+x.c.confirmed,0))],['Công nợ phải thu',money(cs.reduce((s,x)=>s+Math.max(x.c.debt,0),0))],['Tổng lợi nhuận',money(cs.reduce((s,x)=>s+x.c.profit,0))],['Sắp đến hạn',active.filter(x=>x.o.due>=today()&&x.o.due<=datePlus(3)).length],['Quá hạn',active.filter(x=>x.o.due<today()).length]];$('#metrics').innerHTML=metrics.map(x=>`<div class="metric"><small>${x[0]}</small><strong>${x[1]}</strong></div>`).join('');renderReport($('.rTab.active')?.dataset.report||'orders')}
function renderReport(type){let cs=db.orders.filter(o=>!o.deletedAt).map(o=>({o,c:calc(o)}));if(type==='debt')cs=cs.filter(x=>x.c.debt>0).sort((a,b)=>b.c.debt-a.c.debt);if(type==='profit')cs.sort((a,b)=>a.c.profit-b.c.profit);if(type==='staff'){let allocatedByName={};db.orders.filter(o=>!o.deletedAt).forEach(o=>(o.labor||[]).filter(x=>x.status==='Đã chốt').forEach(x=>allocatedByName[x.staff]=(allocatedByName[x.staff]||0)+Number(x.days||0)));let rows=db.staff.map(s=>{let allocated=allocatedByName[s.name]||0,remain=Math.max(0,(s.actualDays||0)-allocated);return `<tr><td><b>${esc(s.name)}</b><br><small>${esc(s.code||s.email)}</small></td><td>${esc(s.dept||'—')}</td><td><span class="role-pill">${s.salaryType==='month'?'Lương tháng':s.salaryType==='hour'?'Lương giờ':'Lương ngày'}</span></td><td>${money(s.hourlySalary)}</td><td>${money(s.dailySalary)}</td><td>${money(s.monthlySalary)}</td><td>${money(s.configAllowance)}</td><td>${money(s.actualAllowance)}</td><td><b>${money(s.rate)}</b></td><td>${s.actualDays||0}</td><td>${allocated}</td><td class="${remain>0?'danger':''}">${remain}</td></tr>`}).join('');$('#reportContent').innerHTML=`<div class="sync-head"><div><b>Lương và nhân sự từ Google Sheet</b><br><small>${db.staffSyncedAt?'Đồng bộ lúc '+new Date(db.staffSyncedAt).toLocaleString('vi-VN')+' · kỳ '+(db.staffSyncedMonth||''):'Chưa đồng bộ'} · Tự đồng bộ khi sang tháng mới</small></div><button id="syncStaff" class="primary">↻ Đồng bộ ngay</button></div>${rows?`<table class="data salary-table"><thead><tr><th>Nhân sự</th><th>Bộ phận</th><th>Loại lương</th><th>Lương giờ</th><th>Lương ngày</th><th>Lương tháng</th><th>PC cấu hình</th><th>PC thực tế tháng</th><th>Đơn giá/công</th><th>Công Sheet</th><th>Đã phân bổ</th><th>Còn lại</th></tr></thead><tbody>${rows}</tbody></table>`:'<div class="empty">Chưa có nhân sự. Bấm Đồng bộ ngay.</div>'}`;$('#syncStaff').onclick=()=>syncStaffFromGoogle();return}let orderRows=cs.map(({o,c})=>`<tr data-open="${o.id}"><td><b>${esc(o.code)}</b></td><td>${esc(o.customer)}</td><td>${o.stage}</td><td>${esc(o.owner)}</td><td>${money(c.revenue)}</td><td>${money(c.confirmed)}</td><td class="${c.debt>0?'danger':''}">${money(c.debt)}</td><td>${money(c.costs)}</td><td class="${c.profit<0?'danger':''}">${money(c.profit)} (${c.margin.toFixed(1)}%)</td><td>${fmtDate(o.due)}</td></tr>`).join('');$('#reportContent').innerHTML=`<table class="data"><thead><tr><th>Mã đơn</th><th>Khách hàng</th><th>Trạng thái</th><th>Phụ trách</th><th>Giá trị</th><th>Đã thu</th><th>Công nợ</th><th>Chi phí</th><th>Lãi/lỗ</th><th>Ngày hẹn</th></tr></thead><tbody>${orderRows}</tbody></table>`;$$('[data-open]').forEach(x=>x.onclick=()=>openOrder(x.dataset.open))}
function parseCSV(text){let rows=[],row=[],cell='',quoted=false;for(let i=0;i<text.length;i++){let ch=text[i];if(ch==='"'){if(quoted&&text[i+1]==='"'){cell+='"';i++}else quoted=!quoted}else if(ch===','&&!quoted){row.push(cell);cell=''}else if((ch==='\n'||ch==='\r')&&!quoted){if(ch==='\r'&&text[i+1]==='\n')i++;row.push(cell);if(row.some(x=>x!==''))rows.push(row);row=[];cell=''}else cell+=ch}if(cell||row.length){row.push(cell);rows.push(row)}return rows}
function num(v){return Number(String(v||'').replace(/[^0-9.-]/g,''))||0}
async function syncStaffFromGoogle(silent=false){let btn=$('#syncStaff');if(btn){btn.disabled=true;btn.textContent='Đang đồng bộ...'}try{let base=`https://docs.google.com/spreadsheets/d/${SHEET_ID}/export?format=csv`,[empRes,payRes]=await Promise.all([fetch(`${base}&gid=${SHEET_EMP_GID}&t=${Date.now()}`),fetch(`${base}&gid=${SHEET_PAYROLL_GID}&t=${Date.now()}`)]);if(!empRes.ok||!payRes.ok)throw new Error('Không đọc được Sheet');let empRows=parseCSV(await empRes.text()),payRows=parseCSV(await payRes.text()),eh=empRows.shift().map(x=>x.trim()),ph=payRows.shift().map(x=>x.trim()),ei=n=>eh.indexOf(n),pi=n=>ph.indexOf(n);let payroll=payRows.map(r=>({month:r[pi('Tháng')],email:String(r[pi('Email')]||'').toLowerCase(),days:num(r[pi('Công Chuẩn')]),allowance:num(r[pi('Tổng Phụ Cấp')])})).filter(x=>x.email),latest=payroll.map(x=>x.month).filter(Boolean).sort().pop()||new Date().toISOString().slice(0,7),payMap=Object.fromEntries(payroll.filter(x=>x.month===latest).map(x=>[x.email,x]));db.staff=empRows.map(r=>{let email=String(r[ei('Email')]||'').trim(),type=String(r[ei('Loại Lương')]||'day').trim().toLowerCase(),hourly=num(r[ei('Lương Giờ')]),daily=num(r[ei('Lương Ngày')]),monthly=num(r[ei('Lương Tháng')]),p=payMap[email.toLowerCase()]||{},allowanceParts=['Phụ Cấp Xăng','Phụ Cấp Ăn Trưa Công Trình','Phụ Cấp Nước Công Trình','Phụ Cấp Cơm','Phụ Cấp Công Trình'].map(n=>num(r[ei(n)])),configAllowance=allowanceParts.reduce((a,b)=>a+b,0),baseRate=type==='month'?monthly/STANDARD_MONTH_DAYS:type==='hour'?hourly*8:daily,allowancePerDay=p.days>0?(p.allowance||0)/p.days:0;return{id:email.toLowerCase(),email,name:r[ei('Họ Tên')],code:r[ei('Mã Nhân Viên')],dept:r[ei('Bộ Phận')],position:r[ei('Chức Vụ')],salaryType:type,hourlySalary:hourly,dailySalary:daily,monthlySalary:monthly,configAllowance,actualAllowance:p.allowance||0,actualDays:p.days||0,month:latest,rate:Math.round(baseRate+allowancePerDay),status:r[ei('Trạng Thái')]}}).filter(x=>x.email&&x.name&&String(x.status).toLowerCase().includes('hoạt động'));db.staffSyncedAt=new Date().toISOString();db.staffSyncedMonth=new Date().toISOString().slice(0,7);save();render();if(!silent)toast(`Đã đồng bộ ${db.staff.length} nhân sự · dữ liệu lương kỳ ${latest}`)}catch(e){if(!silent)toast('Không thể đọc Google Sheet. Kiểm tra quyền chia sẻ hoặc mạng.');console.error(e)}finally{if(btn){btn.disabled=false;btn.textContent='↻ Đồng bộ ngay'}}}
function renderAccounts(){let active=db.users.filter(x=>x.active).length,admins=db.users.filter(x=>x.active&&x.role==='Admin').length;$('#accountStats').innerHTML=[['Tổng tài khoản',db.users.length],['Đang hoạt động',active],['Quản trị viên',admins]].map(x=>`<div class="metric"><small>${x[0]}</small><strong>${x[1]}</strong></div>`).join('');$('#accountsContent').innerHTML=`<table class="data account-table"><thead><tr><th>Người dùng</th><th>Tên đăng nhập</th><th>Vai trò</th><th>Điện thoại</th><th>Trạng thái</th><th>Thao tác</th></tr></thead><tbody>${db.users.map(u=>`<tr><td><div class="account-name"><span class="account-avatar">${esc(u.name.trim()[0]||'?')}</span><b>${esc(u.name)}</b></div></td><td>${esc(u.username)}</td><td><span class="role-pill">${u.role}</span></td><td>${esc(u.phone||'—')}</td><td><span class="status-pill ${u.active?'active':'inactive'}">● ${u.active?'Hoạt động':'Đã khóa'}</span></td><td><div class="row-actions"><button data-edit-user="${u.id}">Sửa</button><button data-toggle-user="${u.id}">${u.active?'Khóa':'Mở'}</button></div></td></tr>`).join('')}</tbody></table>`;$$('[data-edit-user]').forEach(b=>b.onclick=()=>openAccount(b.dataset.editUser));$$('[data-toggle-user]').forEach(b=>b.onclick=()=>toggleAccount(b.dataset.toggleUser))}
function openAccount(id){let u=id?db.users.find(x=>x.id===id):{id:uid(),name:'',username:'',password:'',role:'Quản lý đơn hàng',phone:'',active:true};$('#accountTitle').textContent=id?'Sửa tài khoản':'Tạo tài khoản';$('#accountBody').innerHTML=`<div class="formcontent"><div class="grid"><div class="field span2"><label>Họ và tên *</label><input name="name" value="${esc(u.name)}" required></div><div class="field"><label>Số điện thoại</label><input name="phone" value="${esc(u.phone)}"></div><div class="field"><label>Tên đăng nhập *</label><input name="username" value="${esc(u.username)}" required autocomplete="off"></div><div class="field"><label>Mật khẩu ${id?'(để trống nếu giữ nguyên)':'*'}</label><input type="password" name="password" autocomplete="new-password"></div><div class="field"><label>Vai trò</label><select name="role">${ROLES.map(r=>`<option ${r===u.role?'selected':''}>${r}</option>`)}</select></div></div></div><div class="modalactions"><button value="cancel">Hủy</button><button type="button" id="saveAccount" class="primary">Lưu tài khoản</button></div>`;$('#accountDialog').showModal();$('#saveAccount').onclick=()=>{let f=new FormData($('#accountForm')),name=f.get('name').trim(),username=f.get('username').trim().toLowerCase(),password=f.get('password');if(!name||!username||(!id&&!password))return toast('Vui lòng nhập đủ họ tên, tên đăng nhập và mật khẩu.');if(db.users.some(x=>x.id!==u.id&&x.username.toLowerCase()===username))return toast('Tên đăng nhập đã tồn tại.');u.name=name;u.username=username;u.phone=f.get('phone').trim();u.role=f.get('role');if(password)u.password=password;if(!id){u.createdAt=new Date().toISOString();db.users.push(u)}render();$('#accountDialog').close();toast(id?'Đã cập nhật tài khoản':'Đã tạo tài khoản')}}
function toggleAccount(id){let u=db.users.find(x=>x.id===id);if(u.id===db.currentUser&&u.active)return toast('Không thể khóa tài khoản đang sử dụng.');if(u.role==='Admin'&&u.active&&db.users.filter(x=>x.active&&x.role==='Admin').length===1)return toast('Phải còn ít nhất một tài khoản Admin.');u.active=!u.active;render();toast(u.active?'Đã mở tài khoản':'Đã khóa tài khoản')}
// ===== Gomita Flow workflow extensions =====
var saveStatusTimer;
function setSaveStatus(state,text){let el=$('#saveStatus');if(!el)return;el.className='save-status '+state;el.querySelector('span').textContent=text}
var rawSave=save;
save=function(){setSaveStatus('updating','Đang cập nhật');clearTimeout(saveStatusTimer);try{setSaveStatus('saving','Đang lưu');rawSave();saveStatusTimer=setTimeout(()=>setSaveStatus('done','Đã hoàn thành'),300);setTimeout(()=>setSaveStatus('running','Đang chạy'),1600)}catch(e){setSaveStatus('error','Chưa lưu');throw e}}

function isCompanyExpense(x){return x.payer!=='Khách tự trả tiền'}
calc=function(o){let customer=(o.extras||[]).filter(x=>x.type==='Khách trả').reduce((s,x)=>s+Number(x.amount||0),0),workshop=(o.extras||[]).filter(x=>x.type==='Xưởng chịu').reduce((s,x)=>s+Number(x.amount||0),0),confirmed=(o.payments||[]).filter(x=>x.status==='Đã xác nhận').reduce((s,x)=>s+Number(x.amount||0),0),laborRows=(o.labor||[]).filter(x=>x.status==='Đã chốt'),labor=laborRows.reduce((s,x)=>s+Number(x.days||0)*Number(x.rate||0)+Number(x.tripAllowance||0),0),laborByStage={};laborRows.forEach(x=>laborByStage[x.stage]=(laborByStage[x.stage]||0)+Number(x.days||0)*Number(x.rate||0)+Number(x.tripAllowance||0));let directCosts=(o.costs||[]).filter(isCompanyExpense).reduce((s,x)=>s+Number(x.amount||0),0),costs=directCosts+workshop+labor,revenue=Number(o.quote||0)+customer;return{customer,workshop,confirmed,labor,laborByStage,directCosts,costs,revenue,debt:revenue-confirmed,profit:revenue-costs,margin:revenue?(revenue-costs)/revenue*100:0}}

canAddData=function(type){let r=user().role;if(['Giám đốc','Admin'].includes(r))return true;if(type==='costs')return ['Kế toán','Quản lý đơn hàng','Quản lý sản xuất'].includes(r);if(type==='payments')return ['Kế toán','Quản lý đơn hàng'].includes(r);if(type==='labor')return r==='Quản lý sản xuất';if(type==='extras')return false;return false}

function expenseList(o,edit){let rows=o.costs||[];if(!rows.length)return '<div class="empty">Chưa có khoản chi.</div>';return rows.map(x=>{let status=x.paymentStatus||'Chờ kế toán xác nhận',canConfirm=['Kế toán','Giám đốc','Admin'].includes(user().role)&&status!=='Đã thanh toán';return `<div class="expense-card"><div><b>${esc(x.text)}</b><div class="expense-meta"><span class="mini-pill">${esc(x.expenseKind||'Chi đơn hàng')}</span><span class="mini-pill">${esc(x.category||x.type||'Chi phí khác')}</span><span class="mini-pill">${esc(x.payer||'Công ty trả tiền')}</span><span class="mini-pill ${status==='Đã thanh toán'?'paid':'pending'}">${esc(status)}</span>${x.creditor?`<span class="mini-pill">Nợ: ${esc(x.creditor)}</span>`:''}</div><small>${esc(x.by||'')} · ${x.at?new Date(x.at).toLocaleString('vi-VN'):''}</small></div><b>${money(x.amount)}</b><div class="row-actions">${canConfirm?`<button data-pay-expense="${x.id}" class="primary">Đã thanh toán</button>`:''}${edit&&canAddData('costs')?`<button data-edit-expense="${x.id}">Sửa</button>`:''}</div></div>`}).join('')}

function laborList(o,edit){let rows=o.labor||[];if(!rows.length)return '<div class="empty">Chưa có công thực hiện.</div>';return rows.map(x=>`<div class="listitem"><div><b>${esc(x.staff)} · ${esc(x.stage)}</b><br><small>${x.days||0} công × ${money(x.rate)}${x.tripAllowance?' · Phụ phí '+money(x.tripAllowance):''} · ${esc(x.status)}</small></div><b>${money(Number(x.days||0)*Number(x.rate||0)+Number(x.tripAllowance||0))}</b><div>${edit&&['Quản lý sản xuất','Giám đốc','Admin'].includes(user().role)?`<button data-edit-labor="${x.id}">Sửa</button>`:''}</div></div>`).join('')}

function workLogTable(o){let assignments=o.stageAssignments||[];if(!assignments.length)return '<div class="empty">Chưa có nhật ký công tác.</div>';let movers=[...new Set(assignments.map(x=>x.by||'Không rõ'))],stages=[...new Set(assignments.map(x=>x.completedStage||STAGES[Math.max(0,STAGES.indexOf(x.stage)-1)]))];let cells=stages.map(stage=>`<tr><th>${esc(stage)}</th>${movers.map(m=>{let items=assignments.filter(x=>(x.completedStage||STAGES[Math.max(0,STAGES.indexOf(x.stage)-1)])===stage&&(x.by||'Không rõ')===m);return `<td>${items.map(x=>{let workers=(x.workers||[]).map(w=>{let s=db.staff.find(a=>a.id===w.id);return `${s?.name||w.id}: ${w.days||0} công`}).join('<br>')||esc((x.staff||[]).join(', '));return `<div class="work-cell"><b>${new Date(x.at).toLocaleString('vi-VN')}</b>${workers}</div>`}).join('')}</td>`}).join('')}</tr>`).join('');return `<table class="data worklog-table"><thead><tr><th>Công đoạn</th>${movers.map(x=>`<th>${esc(x)}</th>`).join('')}</tr></thead><tbody>${cells}</tbody></table>`}

var baseTabContent=tabContent;
tabContent=function(o,t,edit){if(t==='extras')return '<div class="empty">Phát sinh đã được gộp vào mục Khoản chi.</div>';if(t==='costs')return `<div class="pagehead"><h3>Khoản chi</h3>${edit&&canAddData('costs')?'<button type="button" class="primary" data-add="costs">＋ Thêm khoản chi</button>':''}</div>${expenseList(o,edit)}`;if(t==='labor')return `<div class="pagehead"><h3>Nhân sự & công</h3>${edit&&canAddData('labor')?'<button type="button" class="primary" data-add="labor">＋ Thêm công</button>':''}</div>${laborList(o,edit)}`;if(t==='logs')return `<h3 class="sectiontitle">Nhật ký công tác</h3>${workLogTable(o)}<h3 class="sectiontitle">Nhật ký hoạt động</h3>${(o.logs||[]).map(l=>`<div class="log"><b>${esc(l.text)}</b><br><small>${esc(l.by)}</small> · <time>${new Date(l.at).toLocaleString('vi-VN')}</time></div>`).join('')||'<div class="empty">Chưa có hoạt động.</div>'}`;let html=baseTabContent(o,t,edit);if(t==='finance'){let c=calc(o);html+=`<h3 class="sectiontitle">Nhân công theo công đoạn</h3><div class="labor-breakdown">${['Ra file','Sản xuất','Lắp đặt'].map(s=>`<div class="finbox"><small>${s}</small><b>${money(c.laborByStage[s]||0)}</b></div>`).join('')}</div>`}return html}

var baseOpenOrder=openOrder;
openOrder=function(id,tab='info'){if(tab==='extras')tab='costs';baseOpenOrder(id,tab);let o=id?db.orders.find(x=>x.id===id):null;let extraTab=$('[data-tab="extras"]'),costTab=$('[data-tab="costs"]');if(extraTab)extraTab.style.display='none';if(costTab)costTab.textContent='Khoản chi';if(tab==='info'){let grid=$('#orderFormBody .formcontent .grid');if(grid&&!grid.querySelector('[name="source"]'))grid.insertAdjacentHTML('beforeend',`<div class="field span2"><label>Nguồn đơn hàng *</label><select name="source"><option value="">-- Chọn nguồn --</option>${ORDER_SOURCES.map(x=>`<option ${x===(o?.source||'')?'selected':''}>${x}</option>`)}</select></div>`)}$$('[data-pay-expense]').forEach(b=>b.onclick=()=>confirmExpense(o,b.dataset.payExpense));$$('[data-edit-expense]').forEach(b=>b.onclick=()=>editExpense(o,b.dataset.editExpense));$$('[data-edit-labor]').forEach(b=>b.onclick=()=>editLabor(o,b.dataset.editLabor))}

var baseSaveOrder=saveOrder;
saveOrder=function(o,isExisting){let source=$('#orderForm [name="source"]')?.value||o.source||'';if(!source)return toast('Vui lòng chọn Nguồn đơn hàng.');o.source=source;baseSaveOrder(o,isExisting)}

var baseQuickAdd=quickAdd;
quickAdd=function(o,type){if(type!=='costs')return baseQuickAdd(o,type);if(!canAddData('costs'))return toast('Bạn không có quyền nhập khoản chi.');$('#quickTitle').textContent='Thêm khoản chi';$('#quickBody').innerHTML=`<div class="formcontent"><div class="grid"><div class="field span2"><label>Nội dung *</label><input name="text" required></div><div class="field"><label>Số tiền *</label><input type="number" name="amount" min="0" required></div><div class="field"><label>Loại chi</label><select name="expenseKind"><option>Chi đơn hàng</option><option>Chi phát sinh</option></select></div><div class="field"><label>Nhóm chi phí</label><select name="category"><option>Sản xuất</option><option>Phụ kiện</option><option>Nhân công</option><option>Vận chuyển</option><option>Chi phí khác</option></select></div><div class="field"><label>Ai thanh toán?</label><select name="payer"><option>Công ty trả tiền</option><option>Nhân viên trả tiền cần công ty thanh tếán</option><option>Khách tự trả tiền</option><option>Công ty trả tiền nhưng nợ NCC</option></select></div><div class="field span2"><label>Công ty đang nợ ai?</label><input name="creditor" placeholder="Nhân viên hoặc nhà cung cấp"></div><div class="field span3"><label>Ghi chú</label><textarea name="note"></textarea></div></div></div><div class="modalactions"><button value="cancel">Hủy</button><button type="button" id="quickSave" class="primary">Lưu khoản chi</button></div>`;$('#quickDialog').showModal();$('#quickSave').onclick=()=>{let f=new FormData($('#quickForm')),x={id:uid(),text:f.get('text').trim(),amount:Number(f.get('amount')),expenseKind:f.get('expenseKind'),category:f.get('category'),payer:f.get('payer'),creditor:f.get('creditor').trim(),paymentStatus:'Chờ kế toán xác nhận',note:f.get('note'),by:user().name,at:new Date().toISOString()};if(!x.text||!x.amount)return toast('Vui lòng nhập nội dung và số tiền.');if((x.payer.includes('Nhân viên')||x.payer.includes('nợ NCC'))&&!x.creditor)return toast('Vui lòng nhập công ty đang nợ ai.');o.costs.push(x);log(o,`Thêm ${x.expenseKind.toLowerCase()}: ${money(x.amount)} · ${x.payer}`);save();render();$('#quickDialog').close();openOrder(o.id,'costs');toast('Đã lưu, đang chờ Kế toán xác nhận')}}

function confirmExpense(o,id){let x=o.costs.find(a=>a.id===id);if(!x||!['Kế toán','Giám đốc','Admin'].includes(user().role))return toast('Chỉ Kế toán được xác nhận thanh toán.');x.paymentStatus='Đã thanh toán';x.confirmedBy=user().name;x.confirmedAt=new Date().toISOString();log(o,`Kế toán xác nhận đã thanh toán ${money(x.amount)}: ${x.text}`);render();openOrder(o.id,'costs')}
function editExpense(o,id){let x=o.costs.find(a=>a.id===id);if(!x)return;$('#quickTitle').textContent='Sửa khoản chi';$('#quickBody').innerHTML=`<div class="formcontent"><div class="grid"><div class="field span2"><label>Nội dung</label><input name="text" value="${esc(x.text)}"></div><div class="field"><label>Số tiền</label><input type="number" name="amount" value="${x.amount}"></div><div class="field span3"><label>Ghi chú</label><textarea name="note">${esc(x.note||'')}</textarea></div></div></div><div class="modalactions"><button value="cancel">Hủy</button><button type="button" id="quickSave" class="primary">Lưu sửa đổi</button></div>`;$('#quickDialog').showModal();$('#quickSave').onclick=()=>{let f=new FormData($('#quickForm'));x.text=f.get('text').trim();x.amount=Number(f.get('amount'));x.note=f.get('note');x.paymentStatus='Chờ kế toán xác nhận';delete x.confirmedBy;log(o,'Sửa khoản chi, chuyển về chờ Kế toán xác nhận');render();$('#quickDialog').close();openOrder(o.id,'costs')}}
function editLabor(o,id){let x=o.labor.find(a=>a.id===id);if(!x)return;$('#quickTitle').textContent='Sửa công & phụ phí';$('#quickBody').innerHTML=`<div class="formcontent"><div class="grid"><div class="field"><label>Nhân sự</label><input value="${esc(x.staff)}" disabled></div><div class="field"><label>Số công</label><input type="number" step="0.25" min="0" name="days" value="${x.days||0}"></div><div class="field"><label>Phụ phí công tác</label><input type="number" min="0" name="tripAllowance" value="${x.tripAllowance||0}"></div><div class="field span3"><label>Ghi chú</label><textarea name="note">${esc(x.note||'')}</textarea></div></div></div><div class="modalactions"><button value="cancel">Hủy</button><button type="button" id="quickSave" class="primary">Lưu công</button></div>`;$('#quickDialog').showModal();$('#quickSave').onclick=()=>{let f=new FormData($('#quickForm'));x.days=Number(f.get('days'));x.tripAllowance=Number(f.get('tripAllowance'));x.note=f.get('note');log(o,`Sửa công ${x.staff}: ${x.days} công, phụ phí ${money(x.tripAllowance)}`);render();$('#quickDialog').close();openOrder(o.id,'labor')}}

canMoveFrom=function(stage){let r=user().role,i=STAGES.indexOf(stage);return ['Giám đốc','Admin'].includes(r)||(r==='Quản lý đơn hàng'&&i<3)||(r==='Quản lý sản xuất'&&i>=3&&i<6)||(r==='Kế toán'&&(stage==='Nghiệm thu'||stage==='Hoàn công'))}
transitionAllowed=function(from,to){let a=STAGES.indexOf(from),b=STAGES.indexOf(to),r=user().role;if(b!==a+1)return 'Chỉ được chuyển sang bước kế tiếp.';if(['Giám đốc','Admin'].includes(r))return '';if(r==='Quản lý đơn hàng'&&b<=3)return '';if(r==='Quản lý sản xuất'&&a>=3&&b<=6)return '';if(r==='Kế toán'&&((from==='Nghiệm thu'&&to==='Hoàn công')||(from==='Hoàn công'&&to==='Lưu trữ')))return '';return `Vai trò ${r} không có quyền chuyển từ ${from} sang ${to}.`}

var baseRequestTransition=requestTransition;
requestTransition=function(id,stage){let o=db.orders.find(x=>x.id===id);if(stage==='Lưu trữ'){let denied=transitionAllowed(o.stage,stage);if(denied)return toast(denied);let c=calc(o),pendingCosts=(o.costs||[]).filter(x=>(x.paymentStatus||'Chờ kế toán xác nhận')!=='Đã thanh toán'),pendingIncome=(o.payments||[]).filter(x=>x.status!=='Đã xác nhận');if(c.debt>0||pendingCosts.length||pendingIncome.length)return toast(`Chưa thể lưu trữ: còn ${money(c.debt)} công nợ khách, ${pendingCosts.length} khoản chi và ${pendingIncome.length} khoản thu chưa xác nhận.`);if(!confirm('Đơn đã đủ dữ liệu. Chuyển về Lưu trữ?'))return;o.stage='Lưu trữ';o.locked=true;log(o,'Kế toán chuyển đơn về Lưu trữ');render();return toast('Đã lưu trữ đơn hàng')}return baseRequestTransition(id,stage)}

moveOrder=function(o,stage,meta){let before=o.stage,people=meta.workers.map(w=>({...db.staff.find(s=>s.id===w.id),days:w.days})).filter(x=>x.name);o.stageAssignments=o.stageAssignments||[];o.stageAssignments.push({id:uid(),stage,completedStage:before,staff:people.map(x=>x.name),workers:meta.workers,note:meta.note,by:user().name,at:new Date().toISOString()});people.forEach(x=>o.labor.push({id:uid(),stage:before,staff:x.name,days:x.days,rate:x.rate,tripAllowance:0,status:'Đã chốt',by:user().name,at:new Date().toISOString()}));o.stage=stage;if(stage==='Nghiệm thu'&&meta.saleOwner)o.owner=meta.saleOwner;log(o,`Hoàn thành ${before}, chuyển sang ${stage} · ${people.map(x=>`${x.name}: ${x.days} công`).join(', ')}`);$('#quickDialog').close();render();toast('Đã chuyển bước, tính công và cập nhật chi phí')}

function exportCsv(){let rows=[['Mã đơn','Khách hàng','Nguồn đơn','Địa chỉ','Điện thoại','Trạng thái','Phụ trách','Giá trị','Đã thu','Công nợ','Chi phí','Lãi lỗ','Ngày hẹn']];db.orders.filter(o=>!o.deletedAt).forEach(o=>{let c=calc(o);rows.push([o.code,o.customer,o.source||'',o.address,o.phone,o.stage,o.owner,c.revenue,c.confirmed,c.debt,c.costs,c.profit,o.due])});let csv='\ufeff'+rows.map(r=>r.map(v=>'"'+String(v).replaceAll('"','""')+'"').join(',')).join('\r\n'),a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8'}));a.download='bao-cao-gomita-'+today()+'.csv';a.click();URL.revokeObjectURL(a.href)}

db.settings=db.settings||{};db.settings.backupUrl=db.settings.backupUrl||DEFAULT_BACKUP_URL;
async function performBackup(silent=false){let url=db.settings.backupUrl;if(!url)return !silent&&toast('Chưa cấu hình URL sao lưu.');setSaveStatus('saving','Đang sao lưu');try{let payload={app:'Gomita Flow',version:2,createdAt:new Date().toISOString(),data:db};await fetch(url,{method:'POST',mode:'no-cors',headers:{'Content-Type':'text/plain;charset=utf-8'},body:JSON.stringify(payload)});db.settings.lastBackupAt=new Date().toISOString();rawSave();setSaveStatus('done','Đã sao lưu');if(!silent)toast('Đã gửi bản sao lưu lên Google Drive');renderBackupList()}catch(e){setSaveStatus('error','Sao lưu lỗi');if(!silent)toast('Sao lưu thất bại. Kiểm tra URL Web App và quyền truy cập.')}}
async function loadBackupList(){let url=db.settings.backupUrl;if(!url)return[];let res=await fetch(`${url}?action=list&t=${Date.now()}`);if(!res.ok)throw new Error('HTTP '+res.status);return await res.json()}
async function renderBackupList(){let box=$('#backupList');if(!box)return;box.innerHTML='<div class="empty">Đang tải danh sách...</div>';try{let rows=await loadBackupList();box.innerHTML=rows.length?rows.map(x=>`<div class="backup-item"><div><b>${esc(x.name)}</b><br><small>${new Date(x.created).toLocaleString('vi-VN')}</small></div><button data-restore="${x.id}">Phục hồi</button></div>`).join(''):'<div class="empty">Chưa có bản sao lưu.</div>';$$('[data-restore]').forEach(b=>b.onclick=()=>restoreBackup(b.dataset.restore))}catch(e){box.innerHTML='<div class="empty danger">Không đọc được danh sách. Kiểm tra triển khai Apps Script.</div>'}}
async function restoreBackup(id){if(!confirm('Phục hồi bản sao lưu này? Dữ liệu hiện tại sẽ được thay thế sau khi tạo một bản sao an toàn.'))return;await performBackup(true);setSaveStatus('saving','Đang phục hồi');try{let res=await fetch(`${db.settings.backupUrl}?action=get&id=${encodeURIComponent(id)}&t=${Date.now()}`),payload=await res.json(),restored=payload.data||payload;if(!restored.orders||!restored.users)throw new Error('Bản sao không hợp lệ');db=restored;db.settings=db.settings||{};db.settings.backupUrl=db.settings.backupUrl||DEFAULT_BACKUP_URL;save();toast('Phục hồi thành công');setTimeout(()=>location.reload(),600)}catch(e){setSaveStatus('error','Phục hồi lỗi');toast('Không thể phục hồi bản sao lưu này.')}}
function maybeAutoBackup(){let last=db.settings?.lastBackupAt?new Date(db.settings.lastBackupAt).getTime():0;if(Date.now()-last>=7*24*60*60*1000)performBackup(true)}

var baseRenderAccounts=renderAccounts;
renderAccounts=function(){baseRenderAccounts();let host=$('#accountsContent');if(!host)return;host.insertAdjacentHTML('afterend',`<div class="backup-box"><div class="pagehead"><div><h3>Sao lưu Google Drive</h3><p>Tự động mỗi 7 ngày · Giữ các bản trong 30 ngày</p></div><span class="status-pill ${db.settings.lastBackupAt?'active':'inactive'}">${db.settings.lastBackupAt?'Lần cuối '+new Date(db.settings.lastBackupAt).toLocaleString('vi-VN'):'Chưa sao lưu'}</span></div><div class="field"><label>URL Google Apps Script Web App</label><input id="backupUrl" value="${esc(db.settings.backupUrl||'')}"></div><div class="backup-actions"><button id="saveBackupUrl">Lưu cấu hình</button><button id="backupNow" class="primary">Sao lưu ngay</button><button id="showBackups">Xem các bản sao lưu</button></div><div id="backupList" class="backup-list"></div></div>`);$('#saveBackupUrl').onclick=()=>{db.settings.backupUrl=$('#backupUrl').value.trim();save();toast('Đã lưu cấu hình sao lưu')};$('#backupNow').onclick=()=>performBackup();$('#showBackups').onclick=()=>renderBackupList()}
var baseEnterApp=enterApp;
var cleanRenderAccounts=renderAccounts;
renderAccounts=function(){$$('#accountsView .backup-box').forEach(x=>x.remove());cleanRenderAccounts()}
var sourceRenderReport=renderReport;
renderReport=function(type){sourceRenderReport(type);if(type==='orders'){let head=$('#reportContent thead tr');if(head&&!head.querySelector('[data-source-col]')){let th=document.createElement('th');th.dataset.sourceCol='1';th.textContent='Nguồn đơn';head.children[2]?.before(th)}$$('#reportContent tbody tr[data-open]').forEach(row=>{if(row.querySelector('[data-source-col]'))return;let o=db.orders.find(x=>x.id===row.dataset.open),td=document.createElement('td');td.dataset.sourceCol='1';td.textContent=o?.source||'—';row.children[2]?.before(td)})}}
var summaryRenderBoard=renderBoard;
renderBoard=function(){summaryRenderBoard();let active=db.orders.filter(o=>!['Hoàn công','Lưu trữ'].includes(o.stage)),val=active.reduce((s,o)=>s+calc(o).revenue,0);$('#summaryLine').textContent=`${active.length} đơn đang chạy · Giá trị ${money(val)}`;let overdue=active.filter(o=>o.due<today()).length,soon=active.filter(o=>o.due>=today()&&o.due<=datePlus(3)).length,unconfirmed=db.orders.reduce((s,o)=>s+(o.payments||[]).filter(p=>p.status!=='Đã xác nhận').length,0),unpaid=db.orders.reduce((s,o)=>s+(o.costs||[]).filter(x=>(x.paymentStatus||'Chờ kế toán xác nhận')!=='Đã thanh toán').length,0);$('#alerts').innerHTML=[[overdue,'đơn quá hạn'],[soon,'đơn sắp đến hạn'],[unconfirmed,'khoản thu chờ xác nhận'],[unpaid,'khoản chi chưa thanh toán']].filter(x=>x[0]).map(x=>`<div class="alert">⚠ ${x[0]} ${x[1]}</div>`).join('')}
renderReports=function(){let cs=db.orders.map(o=>({o,c:calc(o)})),active=cs.filter(x=>!['Hoàn công','Lưu trữ'].includes(x.o.stage)),completed=cs.filter(x=>['Hoàn công','Lưu trữ'].includes(x.o.stage)),metrics=[['Đơn đang chạy',active.length],['Đã hoàn công',completed.length],['Giá trị đang chạy',money(active.reduce((s,x)=>s+x.c.revenue,0))],['Tổng đã thu',money(cs.reduce((s,x)=>s+x.c.confirmed,0))],['Công nợ phải thu',money(cs.reduce((s,x)=>s+Math.max(x.c.debt,0),0))],['Tổng lợi nhuận',money(cs.reduce((s,x)=>s+x.c.profit,0))],['Sắp đến hạn',active.filter(x=>x.o.due>=today()&&x.o.due<=datePlus(3)).length],['Quá hạn',active.filter(x=>x.o.due<today()).length]];$('#metrics').innerHTML=metrics.map(x=>`<div class="metric"><small>${x[0]}</small><strong>${x[1]}</strong></div>`).join('');renderReport($('.rTab.active')?.dataset.report||'orders')}
enterApp=function(){baseEnterApp();setTimeout(()=>maybeAutoBackup(),1200)}
// Các hộp thoại tự đóng sau khi lưu; không khóa nút toàn cục vì dễ làm lần thao tác kế tiếp bị trễ.
function toast(s){let x=document.createElement('div');x.className='toast';x.textContent=s;$('#toast').append(x);setTimeout(()=>x.remove(),2600)}
$$('.nav').forEach(b=>b.onclick=()=>{if(b.dataset.view==='accounts'&&user().role!=='Admin')return toast('Chỉ Admin được quản lý tài khoản.');if(b.dataset.view==='trash'&&user().role!=='Admin')return toast('Chỉ Admin được truy cập Thùng rác.');$$('.nav,.view').forEach(x=>x.classList.remove('active'));b.classList.add('active');$('#'+b.dataset.view+'View').classList.add('active');if(b.dataset.view==='trash')renderTrash();});$$('.rTab').forEach(b=>b.onclick=()=>{$$('.rTab').forEach(x=>x.classList.remove('active'));b.classList.add('active');renderReport(b.dataset.report)});$('#newOrder').onclick=()=>openOrder();$('#newAccount').onclick=()=>openAccount();['search','statusFilter','priorityFilter'].forEach(id=>$('#'+id).oninput=renderBoard);$('#exportCsv').onclick=exportCsv;$('#printReport').onclick=()=>window.print();$('#loginForm').onsubmit=e=>{e.preventDefault();let f=new FormData(e.currentTarget),username=f.get('username').trim().toLowerCase(),account=db.users.find(x=>x.username.toLowerCase()===username);if(!account||account.password!==f.get('password'))return showLogin('Tên đăng nhập hoặc mật khẩu không đúng.');if(!account.active)return showLogin('Tài khoản này đã bị khóa. Vui lòng liên hệ Admin.');db.currentUser=account.id;enterApp()};$('#logoutButton').onclick=()=>showLogin();$('#togglePassword').onclick=()=>{let p=$('#loginPassword');p.type=p.type==='password'?'text':'password'};$('#recoverAdmin').onclick=()=>{if(!confirm('Khôi phục tài khoản Admin về admin / 123456? Dữ liệu đơn hàng vẫn được giữ nguyên.'))return;let a=db.users.find(x=>x.role==='Admin')||db.users.find(x=>x.username==='admin');if(!a){a={...INITIAL_ADMIN};db.users.push(a)}Object.assign(a,{username:'admin',password:'123456',role:'Admin',active:true});db.currentUser=a.id;save();showLogin('Đã khôi phục. Đăng nhập bằng admin / 123456.')};init();
